import { useNavigate } from 'react-router-dom';
import logo from '../assets/blouge.svg';

export default function Navbar({ darkMode, toggleDarkMode }) {
    const navigate = useNavigate();

    return (
        <nav className="navbar">
            <div className="nav-left">
                <button onClick={() => navigate('/groups')}>Accueil</button>
                <button onClick={toggleDarkMode}>
                    {darkMode ? "☀️ Clair" : "🌙 Sombre"}
                </button>
            </div>

            <div className="nav-right" onClick={() => navigate('/')}>
                <img src={logo} alt="Blouge Logo" className="nav-logo" />
                <span className="nav-title">Blouge</span>
            </div>
        </nav>
    );
}
